.page {
  min-height: 100vh;
  display: grid;
  place-items: center;
  padding: 32px;
  background: linear-gradient(180deg, #0f172a 0%, #111827 100%);
  color: #e5e7eb;
  font-family: var(--font-geist-sans);
}

.card {
  width: min(100%, 760px);
  display: grid;
  gap: 16px;
  padding: 32px;
  border: 1px solid rgba(148, 163, 184, 0.2);
  border-radius: 24px;
  background: rgba(15, 23, 42, 0.88);
  box-shadow: 0 24px 80px rgba(0, 0, 0, 0.35);
}

.eyebrow {
  font-size: 0.85rem;
  font-weight: 700;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  color: #38bdf8;
}

.card h1 {
  font-size: clamp(2rem, 4vw, 3rem);
  line-height: 1.1;
}

.description {
  color: #cbd5e1;
  line-height: 1.6;
}

.description code {
  font-family: var(--font-geist-mono);
  color: #f8fafc;
}

.label {
  font-weight: 600;
}

.textarea {
  width: 100%;
  resize: vertical;
  min-height: 112px;
  padding: 14px 16px;
  border: 1px solid #334155;
  border-radius: 16px;
  background: #020617;
  color: #e2e8f0;
  font: inherit;
}

.button {
  width: fit-content;
  padding: 12px 18px;
  border: none;
  border-radius: 999px;
  background: #38bdf8;
  color: #082f49;
  font-weight: 700;
  cursor: pointer;
}

.button:disabled {
  cursor: not-allowed;
  opacity: 0.6;
}

.outputPanel {
  display: grid;
  gap: 12px;
  margin-top: 8px;
  padding: 20px;
  border-radius: 20px;
  background: rgba(2, 6, 23, 0.85);
  border: 1px solid rgba(56, 189, 248, 0.15);
}

.outputHeader {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
}

.outputHeader h2 {
  font-size: 1rem;
}

.badge {
  padding: 4px 10px;
  border-radius: 999px;
  background: rgba(16, 185, 129, 0.18);
  color: #86efac;
  font-size: 0.8rem;
  font-weight: 700;
  text-transform: uppercase;
}

.output {
  white-space: pre-wrap;
  word-break: break-word;
  min-height: 180px;
  color: #e2e8f0;
  font-family: var(--font-geist-mono);
  line-height: 1.7;
}

.error {
  color: #fca5a5;
}

