import { initTRPC } from "@trpc/server";
import superjson from "superjson";

const t = initTRPC.create({
  transformer: superjson,
});

export const createTRPCRouter = t.router;
export const publicProcedure = t.procedure;

import { z } from "zod";

import { createTRPCRouter, publicProcedure } from "../trpc";

async function* generateChatChunks(prompt: string): AsyncGenerator<string> {
  const normalizedPrompt = prompt.trim() || "Tell me something about tRPC streaming.";
  const parts = [
    `You said: ${normalizedPrompt}`,
    "Streaming over standard HTTP works with AsyncGenerator responses.",
    "Each yielded chunk arrives progressively in the browser.",
    "This pattern is a good fit for LLM tokens or long-running tasks.",
  ];

  for (const part of parts) {
    await new Promise((resolve) => setTimeout(resolve, 600));
    yield `${part} `;
  }
}

export const appRouter = createTRPCRouter({
  chatStream: publicProcedure
    .input(z.object({ prompt: z.string().min(1) }))
    .query(async function* ({ input }) {
      yield* generateChatChunks(input.prompt);
    }),
});

export type AppRouter = typeof appRouter;

import { fetchRequestHandler } from "@trpc/server/adapters/fetch";

import { appRouter } from "@/src/server/routers/_app";

const handler = (request: Request) =>
  fetchRequestHandler({
    endpoint: "/api/trpc",
    req: request,
    router: appRouter,
    createContext: () => ({}),
  });

export { handler as GET, handler as POST };

"use client";

import { QueryClient } from "@tanstack/react-query";
import { createTRPCClient, httpBatchStreamLink } from "@trpc/client";
import superjson from "superjson";

import type { AppRouter } from "@/src/server/routers/_app";

export const queryClient = new QueryClient();

export const trpcClient = createTRPCClient<AppRouter>({
  links: [
    httpBatchStreamLink({
      transformer: superjson,
      url: "/api/trpc",
    }),
  ],
});

"use client";

import { useCallback, useState } from "react";

import { trpcClient } from "@/src/trpc/client";

import styles from "./page.module.css";

const defaultPrompt = "Explain why AsyncGenerator streaming is useful in tRPC v11.";

export default function Home() {
  const [prompt, setPrompt] = useState(defaultPrompt);
  const [streamedText, setStreamedText] = useState("");
  const [isStreaming, setIsStreaming] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const startStream = useCallback(async () => {
    setIsStreaming(true);
    setStreamedText("");
    setError(null);

    try {
      const stream = await trpcClient.chatStream.query({ prompt });

      for await (const chunk of stream) {
        setStreamedText((current) => current + chunk);
      }
    } catch (cause) {
      setError(cause instanceof Error ? cause.message : "Streaming failed");
    } finally {
      setIsStreaming(false);
    }
  }, [prompt]);

  return (
    <main className={styles.page}>
      <section className={styles.card}>
        <p className={styles.eyebrow}>tRPC v11 AsyncGenerator Streaming</p>
        <h1>Stream chat chunks over standard HTTP</h1>
        <p className={styles.description}>
          This demo uses <code>httpBatchStreamLink</code> on the client and an
          <code> AsyncGenerator</code> tRPC procedure on the server.
        </p>

        <label className={styles.label} htmlFor="prompt">
          Prompt
        </label>
        <textarea
          id="prompt"
          className={styles.textarea}
          value={prompt}
          onChange={(event) => setPrompt(event.target.value)}
          rows={4}
        />

        <button
          className={styles.button}
          onClick={startStream}
          disabled={isStreaming || !prompt.trim()}
          type="button"
        >
          {isStreaming ? "Streaming..." : "Start stream"}
        </button>

        <div className={styles.outputPanel}>
          <div className={styles.outputHeader}>
            <h2>Streamed response</h2>
            {isStreaming ? <span className={styles.badge}>live</span> : null}
          </div>

          <pre className={styles.output}>
            {streamedText || "The streamed chunks will appear here in real time."}
          </pre>
        </div>

        {error ? <p className={styles.error}>{error}</p> : null}
      </section>
    </main>
  );
}

.page {
  min-height: 100vh;
  display: grid;
  place-items: center;
  padding: 32px;
  background: linear-gradient(180deg, #0f172a 0%, #111827 100%);
  color: #e5e7eb;
  font-family: var(--font-geist-sans);
}

.card {
  width: min(100%, 760px);
  display: grid;
  gap: 16px;
  padding: 32px;
  border: 1px solid rgba(148, 163, 184, 0.2);
  border-radius: 24px;
  background: rgba(15, 23, 42, 0.88);
  box-shadow: 0 24px 80px rgba(0, 0, 0, 0.35);
}

.eyebrow {
  font-size: 0.85rem;
  font-weight: 700;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  color: #38bdf8;
}

.card h1 {
  font-size: clamp(2rem, 4vw, 3rem);
  line-height: 1.1;
}

.description {
  color: #cbd5e1;
  line-height: 1.6;
}

.description code {
  font-family: var(--font-geist-mono);
  color: #f8fafc;
}

.label {
  font-weight: 600;
}

.textarea {
  width: 100%;
  resize: vertical;
  min-height: 112px;
  padding: 14px 16px;
  border: 1px solid #334155;
  border-radius: 16px;
  background: #020617;
  color: #e2e8f0;
  font: inherit;
}

.button {
  width: fit-content;
  padding: 12px 18px;
  border: none;
  border-radius: 999px;
  background: #38bdf8;
  color: #082f49;
  font-weight: 700;
  cursor: pointer;
}

.button:disabled {
  cursor: not-allowed;
  opacity: 0.6;
}

.outputPanel {
  display: grid;
  gap: 12px;
  margin-top: 8px;
  padding: 20px;
  border-radius: 20px;
  background: rgba(2, 6, 23, 0.85);
  border: 1px solid rgba(56, 189, 248, 0.15);
}

.outputHeader {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
}

.outputHeader h2 {
  font-size: 1rem;
}

.badge {
  padding: 4px 10px;
  border-radius: 999px;
  background: rgba(16, 185, 129, 0.18);
  color: #86efac;
  font-size: 0.8rem;
  font-weight: 700;
  text-transform: uppercase;
}

.output {
  white-space: pre-wrap;
  word-break: break-word;
  min-height: 180px;
  color: #e2e8f0;
  font-family: var(--font-geist-mono);
  line-height: 1.7;
}

.error {
  color: #fca5a5;
}

@media (max-width: 640px) {
  .page {
    padding: 16px;
  }

  .card {
    padding: 24px;
  }
}

